通用事件.OnEvent-通用事件:
### OnEvent-通用事件 

```cpp
void OnEvent(StringRef name, MapRef<String, String> value)
```

**说明：**

> 通用事件。 

**参数：**

| 参数名 | 类型 | 说明 |
| ------ | ---- | ---- |
| name   | StringRef             | 事件名称 |
| value  | MapRef<String,String> | 事件内容 |

**返回值：** 无

**示例：**

```cpp
Vars
    Global Integer count(0);

Events
    OnInit()
    {
        SubscribeEvent("自定义事件测试");//订阅公共自定义事件
        SubscribeEvent(A_GetOrderCreateSource);//订阅当前操作源的自定义事件
        Print("SubscribeEvent:" + A_GetOrderCreateSource);
    }

    OnReady()
    {
        Map<String,String> test;
        test["操作源"] = A_GetOrderCreateSource;
        test["次数"] = "1";
        test["测试键名"] = "测试内容";
        //发布自定义事件到当前操作源
        PublishEvent("自定义事件测试", test, "所有订阅者");
    }

    //通用事件触发函数，参数evtName为事件名称，参数evtValue为事件内容
    OnEvent(StringRef evtName,MapRef<String,String> evtValue) 
    {
        Print("eventName:" + evtName + ",value:" + TextMap(evtValue));
        //过滤当前操作源下发布的事件
        if(evtValue["操作源"] != A_GetOrderCreateSource)
        {
            Map<String,String> test;
            test["操作源"] = A_GetOrderCreateSource;
            test["次数"] = Text(count);//次数加1
            test["测试键名"] = "测试内容";
            if(Value(test["次数"]) <= 10)//上限限制
            {
                //发布事件来源的自定义事件给事件来源的订阅者
                PublishEvent(evtValue["操作源"], test, evtValue["操作源"]);
                Print("PublishEvent,操作源:" + test["操作源"] + ",次数:" + test["次数"]);
                count = count + 1;
            }
        }
    }
```

