**示例：**

```cpp
Vars
    Global Integer count(0);
    Dic<Integer> dicValue("restart", True);

Events
    OnInit()
    {
        count = count + 1;
        FileAppend(FormulaName + ".txt", "OnInit,count:" + Text(count));
    }

    OnReady()
    {
        count = count + 1;
        FileAppend(FormulaName + ".txt", "OnReady,count:" + Text(count) + ",dic value:" + Text(dicValue[0]));
        if(InvalidInteger == dicValue[0])
        {
            ReStart();
            FileAppend(FormulaName + ".txt", "ReStart");
            dicValue[0] = 10;
        }
        Else
        {
            Bool ret = DeleteDicValue("restart");
            FileAppend(FormulaName + ".txt", "DeleteDicValue:" + IIFString(ret, "True", "False"));
        }
    }
```

